import{_ as t,o as e,c as n,a3 as s}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"部署模式对比","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/deploy-comparison.md","filePath":"middleware/kafka/deploy-comparison.md","lastUpdated":1780474278000}'),d={name:"middleware/kafka/deploy-comparison.md"};function r(l,a,o,i,p,h){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="bu-shu-mo-shi-dui-bi" tabindex="-1">部署模式对比 <a class="header-anchor" href="#bu-shu-mo-shi-dui-bi" aria-label="Permalink to &quot;部署模式对比&quot;">​</a></h1><p>Kafka 支持两种部署模式（单节点、集群），以及两种元数据管理方案（ZooKeeper、KRaft）。</p><h2 id="gai-shu" tabindex="-1">概述 <a class="header-anchor" href="#gai-shu" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>Broker 数</th><th>高可用</th><th>水平扩展</th><th>适用场景</th></tr></thead><tbody><tr><td>单节点</td><td>1</td><td>❌</td><td>❌</td><td>本地开发、测试</td></tr><tr><td>集群（ZK）</td><td>≥ 3</td><td>✅</td><td>✅</td><td>生产环境（历史遗留）</td></tr><tr><td>集群（KRaft）</td><td>≥ 3</td><td>✅</td><td>✅</td><td>生产环境（推荐，Kafka 3.7+）</td></tr></tbody></table><h2 id="dan-jie-dianstandalone" tabindex="-1">单节点（Standalone） <a class="header-anchor" href="#dan-jie-dianstandalone" aria-label="Permalink to &quot;单节点（Standalone）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────┐</span></span>
<span class="line"><span>│     Broker :9092   │   KRaft 模式：Broker + Controller 合一</span></span>
<span class="line"><span>│  (broker,controller)│</span></span>
<span class="line"><span>└───────────────────┘</span></span></code></pre></div><p><strong>优点</strong>：</p><ul><li>部署最简单，一条 Docker 命令启动</li><li>资源占用少，适合本地开发和 CI</li><li>管理零成本</li></ul><p><strong>缺点</strong>：</p><ul><li>无高可用，宕机即不可用</li><li>无数据冗余，副本因子只能为 1</li><li>吞吐受限于单机</li></ul><p><strong>适用</strong>：本地开发、单元测试、CI 流水线。</p><h2 id="ji-qunkraft-tui-jian" tabindex="-1">集群（KRaft 推荐） <a class="header-anchor" href="#ji-qunkraft-tui-jian" aria-label="Permalink to &quot;集群（KRaft 推荐）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ┌──────────────┐  ┌──────────────┐  ┌──────────────┐</span></span>
<span class="line"><span>    │  Broker 1    │  │  Broker 2    │  │  Broker 3    │</span></span>
<span class="line"><span>    │  controller  │  │  controller  │  │  controller  │   KRaft Quorum</span></span>
<span class="line"><span>    │  :9092       │  │  :9093       │  │  :9094       │</span></span>
<span class="line"><span>    └──────────────┘  └──────────────┘  └──────────────┘</span></span>
<span class="line"><span>         ▲  ▲  ▲          ▲  ▲  ▲          ▲  ▲  ▲</span></span>
<span class="line"><span>         │  │  │          │  │  │          │  │  │</span></span>
<span class="line"><span>    Partition-0  Partition-1  Partition-2  (replication-factor=3)</span></span></code></pre></div><p><strong>优点</strong>：</p><ul><li>高可用：Broker 故障自动切换 Leader，服务不中断</li><li>数据冗余：多副本存储，不丢数据</li><li>水平扩展：增加 Broker 线性提升吞吐</li><li>无外部依赖：KRaft 模式自包含，运维简单</li></ul><p><strong>缺点</strong>：</p><ul><li>至少 3 节点，资源成本较高</li><li>需配置 Controller Quorum 和网络互通</li><li>KRaft 模式 Controller 节点负载较高（管理所有元数据）</li></ul><p><strong>适用</strong>：所有生产环境，中大规模应用。</p><h2 id="kraft-vs-zookeeper" tabindex="-1">KRaft vs ZooKeeper <a class="header-anchor" href="#kraft-vs-zookeeper" aria-label="Permalink to &quot;KRaft vs ZooKeeper&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比维度</th><th>ZooKeeper 模式</th><th>KRaft 模式</th></tr></thead><tbody><tr><td>外部依赖</td><td>ZooKeeper 集群（≥ 3 节点）</td><td>无，Kafka 内置 Raft</td></tr><tr><td>进程数</td><td>Kafka + ZK 两套系统</td><td>仅 Kafka 一套</td></tr><tr><td>元数据存储</td><td>ZK 树形结构</td><td>Kafka 内部 Topic <code>__cluster_metadata</code></td></tr><tr><td>元数据传播</td><td>ZK Watch（慢）</td><td>Raft 日志复制（快）</td></tr><tr><td>Controller 故障恢复</td><td>从 ZK 重建（耗时 10-60s）</td><td>Raft Leader 选举（&lt; 1s）</td></tr><tr><td>Partition 数上限</td><td>~200K（ZK 节点数瓶颈）</td><td>≥ 2M</td></tr><tr><td>Kafka 版本</td><td>所有版本</td><td>3.3+ 生产可用，4.0+ 仅支持 KRaft</td></tr><tr><td>迁移支持</td><td>—</td><td>ZK→KRaft 在线迁移（3.5+）</td></tr></tbody></table><h2 id="xuan-xing-jue-ce" tabindex="-1">选型决策 <a class="header-anchor" href="#xuan-xing-jue-ce" aria-label="Permalink to &quot;选型决策&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>是否需要高可用？</span></span>
<span class="line"><span>├── 否 → 单节点（开发/测试）</span></span>
<span class="line"><span>└── 是</span></span>
<span class="line"><span>    └── Kafka 版本？</span></span>
<span class="line"><span>        ├── ≤ 3.2 → 集群（ZooKeeper）</span></span>
<span class="line"><span>        └── ≥ 3.3 → 集群（KRaft，推荐）</span></span></code></pre></div><table tabindex="0"><thead><tr><th>条件</th><th>推荐模式</th></tr></thead><tbody><tr><td>本地开发、测试</td><td>单节点 KRaft</td></tr><tr><td>生产环境，Kafka ≥ 3.3</td><td>KRaft 集群</td></tr><tr><td>生产环境，Kafka ≤ 3.2</td><td>ZK 集群 + 计划迁移</td></tr><tr><td>大容量场景（&gt; 200K Partition）</td><td>KRaft 集群</td></tr></tbody></table><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#kraft" target="_blank" rel="noreferrer">Apache Kafka KRaft Overview</a></li><li><a href="https://kafka.apache.org/documentation/#zk_migration" target="_blank" rel="noreferrer">KRaft ZooKeeper Migration</a></li></ul>`,25)])])}const f=t(d,[["render",r]]);export{u as __pageData,f as default};
